const body = $input.first().json.body;
const messages = body.messages || [];

// Extract system message
const systemMsg = messages.find(m => m.role === 'system');
const systemPrompt = systemMsg ? systemMsg.content : '';

// Build user prompt from non-system messages
const nonSystem = messages.filter(m => m.role !== 'system');
let userPrompt = '';

if (nonSystem.length === 1) {
  userPrompt = nonSystem[0].content;
} else if (nonSystem.length > 1) {
  const history = nonSystem.slice(0, -1).map(m =>
    `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}`
  );
  const last = nonSystem[nonSystem.length - 1];
  userPrompt = `Previous conversation:\n${history.join('\n')}\n\nCurrent instruction: ${last?.content || ''}`;
}

if (!userPrompt) {
  throw new Error('No user message found in messages array');
}

return [{ json: { systemPrompt, userPrompt } }];

const output = $input.first().json?.output;
if (!output) {
  throw new Error('AI Agent returned empty output');
}
return [{ json: { content: output } }];
